// Calculate the digest window - since last digest or default 8 hours
const defaultHours = 8;
const sinceTimestamp = new Date(Date.now() - defaultHours * 60 * 60 * 1000).toISOString();
return [{ json: { since_timestamp: sinceTimestamp, digest_time: new Date().toISOString() } }];

// Gather all inputs from parallel branches
const important = $('Fetch Important Emails').all().map(i => i.json).filter(i => i.message_id);
const actions = $('Fetch Unresolved Actions').all().map(i => i.json).filter(i => i.id);
const unreadData = $('Fetch Unread Count').first().json;
const finance = $('Fetch Finance Reminders').all().map(i => i.json).filter(i => i.message_id);
const stats = $('Fetch Category Stats').all().map(i => i.json).filter(i => i.category);

const digestTime = $('Get Digest Window').first().json.digest_time;
const unreadCount = unreadData.unread_count || 0;

// Build HTML
let html = `<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto;">`;
html += `<h1 style="color: #1a73e8;">Gmail Inbox Digest</h1>`;
html += `<p style="color: #666;">Generated: ${new Date(digestTime).toLocaleString()}</p>`;
html += `<p><strong>Unread emails (24h):</strong> ${unreadCount}</p>`;

// Category breakdown
if (stats.length > 0) {
  html += `<h2>Category Breakdown</h2><table style="border-collapse: collapse; width: 100%;">`;
  html += `<tr style="background: #f0f0f0;"><th style="padding: 8px; text-align: left;">Category</th><th style="padding: 8px;">Count</th></tr>`;
  for (const s of stats) {
    html += `<tr><td style="padding: 8px; border-bottom: 1px solid #eee;">${s.category}</td><td style="padding: 8px; border-bottom: 1px solid #eee; text-align: center;">${s.count}</td></tr>`;
  }
  html += `</table>`;
}

// Important emails
if (important.length > 0) {
  html += `<h2>Important Emails (${important.length})</h2><table style="border-collapse: collapse; width: 100%;">`;
  html += `<tr style="background: #f0f0f0;"><th style="padding: 8px; text-align: left;">From</th><th style="padding: 8px; text-align: left;">Subject</th><th style="padding: 8px;">Priority</th><th style="padding: 8px; text-align: left;">Summary</th></tr>`;
  for (const e of important.slice(0, 15)) {
    const priority = e.priority_score || '-';
    const color = priority >= 8 ? '#d93025' : priority >= 5 ? '#f9ab00' : '#34a853';
    html += `<tr><td style="padding: 8px; border-bottom: 1px solid #eee;">${(e.sender || '').substring(0, 40)}</td><td style="padding: 8px; border-bottom: 1px solid #eee;">${(e.subject || '').substring(0, 60)}</td><td style="padding: 8px; border-bottom: 1px solid #eee; text-align: center; color: ${color}; font-weight: bold;">${priority}</td><td style="padding: 8px; border-bottom: 1px solid #eee; font-size: 12px;">${(e.ai_summary || '').substring(0, 100)}</td></tr>`;
  }
  html += `</table>`;
}

// Action items
if (actions.length > 0) {
  html += `<h2>Open Action Items (${actions.length})</h2><ul>`;
  for (const a of actions.slice(0, 10)) {
    const deadline = a.deadline ? ` (due: ${a.deadline})` : '';
    html += `<li>${a.description}${deadline}</li>`;
  }
  html += `</ul>`;
}

// Finance reminders
if (finance.length > 0) {
  html += `<h2>Finance/Admin (${finance.length})</h2><ul>`;
  for (const f of finance.slice(0, 5)) {
    html += `<li><strong>${(f.sender || '').substring(0, 30)}:</strong> ${(f.subject || '').substring(0, 60)}</li>`;
  }
  html += `</ul>`;
}

html += `<hr><p style="color: #999; font-size: 11px;">Gmail Admin Digest - Automated by n8n</p></div>`;

return [{ json: { digest_html: html, email_count: important.length, action_count: actions.length, unread_count: unreadCount } }];
